// Test: moderate conditions should return yellow (caution) level
async function testComputeSeaStatusYellow() {
  const result = functions.call('computeSeaStatus', {
    windSpeed: 22,      // fresh to strong wind — 25 penalty
    windGusts: 30,      // gusty
    waveHeight: 2.5,    // moderate seas — 15 penalty
    precipitation: 2,   // light rain — 5 penalty
    pressure: 1005,     // normal-ish
    cloudCover: 70
  });

  assertEquals(result.level, 'yellow', 'Moderate conditions should be yellow');
  assertEquals(result.label, 'Caution');
  assert(result.score >= 40 && result.score < 70, 'Yellow score should be 40-69, got ' + result.score);
  assert(result.reasons.length > 0, 'Should have penalty reasons');
}
